sql:
SELECT actions.action_id, actions.action_date, actions.action_type, actions.description, users.user_name AS taken_by
FROM actions
INNER JOIN users ON actions.user_id = users.user_id;

SELECT status_id, status_name, description, is_final
FROM statuses
WHERE status_id = (SELECT status_id FROM issues WHERE issue_id = 0);

external_knowledge:
- 'Fastest average resolution time' implies the shortest average time taken to resolve issues; 
- 'Last week' refers to the period between the current date and 7 days ago; 
- An 'escalated issue' is an issue that requires additional attention or support; 
- 'Last action date' refers to the date and time of the last action taken on an issue.
